// ── Availability component ────────────────────────────────────────────────────
function Availability() {
  const now    = new Date();
  const MONTHS = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
  const YEARS  = Array.from({length:10},(_,i) => now.getFullYear()-2+i);

  const [mo,  setMo]  = useState(now.getMonth());
  const [yr,  setYr]  = useState(now.getFullYear());
  const [sel, setSel] = useState(new Set([now.getDate()]));
  const [uDate,setUD] = useState("");
  const [from, setFr] = useState("");
  const [to,   setTo] = useState("");

  const first   = new Date(yr, mo, 1).getDay();
  const total   = new Date(yr, mo+1, 0).getDate();
  const blanks  = Array(first).fill(null);
  const days    = Array.from({length:total}, (_,i) => i+1);
  const filled  = blanks.length + days.length;
  const trailing = filled % 7 === 0 ? 0 : 7 - (filled % 7);
  const trailDays = Array.from({length:trailing}, (_,i) => i+1);

  const toggle = d => setSel(p => { const n=new Set(p); n.has(d)?n.delete(d):n.add(d); return n; });
  const prev   = () => mo===0 ? (setMo(11), setYr(y=>y-1)) : setMo(m=>m-1);
  const next   = () => mo===11 ? (setMo(0), setYr(y=>y+1)) : setMo(m=>m+1);

  return (
    <div style={s.calOuter}>
      <div style={s.panTit}>Availability</div>

      {/* ── Boxed calendar ── */}
      <div style={s.calBox}>
        {/* nav row */}
        <div style={s.calNav}>
          <button style={s.calNavBtn} onClick={prev}>‹</button>
          <select style={s.calSel} value={mo} onChange={e=>setMo(+e.target.value)}>
            {MONTHS.map((m,i)=><option key={m} value={i}>{m}</option>)}
          </select>
          <select style={s.calSel} value={yr} onChange={e=>setYr(+e.target.value)}>
            {YEARS.map(y=><option key={y}>{y}</option>)}
          </select>
          <button style={s.calNavBtn} onClick={next}>›</button>
        </div>

        {/* day grid */}
        <div style={s.calGrid}>
          {["Su","Mo","Tu","We","Th","Fr","Sa"].map(d =>
            <div key={d} style={s.calHd}>{d}</div>
          )}
          {blanks.map((_,i) => <div key={"b"+i} />)}
          {days.map(d => (
            <button key={d} onClick={()=>toggle(d)}
              style={sel.has(d) ? s.calAct : s.calDy}>
              {d}
            </button>
          ))}
          {trailDays.map(d => (
            <button key={"t"+d} style={s.calFade}>{d}</button>
          ))}
        </div>
      </div>
      {/* ── end boxed calendar ── */}

      {/* ── Unavailable section — outside the box ── */}
      <div style={s.unavTitle}>Unavailable on:</div>
      <input
        style={s.unavInp}
        placeholder="Date"
        value={uDate}
        onChange={e=>setUD(e.target.value)}
      />
      <span style={s.tmLbl}>Timing</span>
      <div style={s.tmRow}>
        <input style={s.tmInp} placeholder="From" value={from} onChange={e=>setFr(e.target.value)}/>
        <input style={s.tmInp} placeholder="To"   value={to}   onChange={e=>setTo(e.target.value)}/>
      </div>
    </div>
  );
}

